                    </div>
                    <div className="w-px h-8 bg-white/20" />
                    <div className="flex flex-col items-center">
                        <span className="text-white font-bold text-lg">4K</span>
                        <span>Simulators</span>
                    </div>
                    <div className="w-px h-8 bg-white/20" />
                    <div className="flex flex-col items-center">
                        <span className="text-white font-bold text-lg">24/7</span>
                        <span>Access</span>
                    </div>
                </div>
            </div>
        </section>
    );
