                        <li className="flex items-center gap-3 text-white/80">
                            <Check className="w-5 h-5 text-primary" />
                            <span>Adjustable weather and course conditions</span>
                        </li>
                        <li className="flex items-center gap-3 text-white/80">
                            <Check className="w-5 h-5 text-primary" />
                            <span>Putting that actually feels real</span>
                        </li>
                    </ul>
                </div>
            </div>
        </Section>
    );
}

